// Cross-incident correlation and escalation logic
const items = $input.all();
const predictions = items[0]?.json?.predictions || {};
const alerts = items[1]?.json?.alerts || {};

const escalations = [];

// Check for compound incidents (multiple high-severity across types)
const criticalTypes = [];
for (const [type, preds] of Object.entries(predictions)) {
  const criticals = (preds || []).filter(p => p.severity === 'critical' || p.probability > 0.85);
  if (criticals.length > 0) criticalTypes.push(type);
}

if (criticalTypes.length >= 2) {
  escalations.push({
    level: 'compound_emergency',
    types: criticalTypes,
    message: `COMPOUND EMERGENCY: ${criticalTypes.length} simultaneous critical incidents (${criticalTypes.join(', ')})`,
    action: 'activate_emergency_operations_centre'
  });
}

// Check for cascading risks
if (criticalTypes.includes('flood') && criticalTypes.includes('power_outage')) {
  escalations.push({
    level: 'cascading_risk',
    types: ['flood', 'power_outage'],
    message: 'CASCADING RISK: Flood + power outage combination — critical infrastructure at risk',
    action: 'deploy_backup_generators'
  });
}

if (criticalTypes.includes('severe_storm') && criticalTypes.includes('infrastructure_damage')) {
  escalations.push({
    level: 'cascading_risk',
    types: ['severe_storm', 'infrastructure_damage'],
    message: 'CASCADING RISK: Storm damage to infrastructure — transport disruption likely',
    action: 'close_affected_routes'
  });
}

return [{ json: {
  evaluatedAt: new Date().toISOString(),
  totalPredictionTypes: Object.keys(predictions).length,
  totalAlertTypes: Object.keys(alerts).length,
  criticalTypes,
  escalations,
  hasEscalations: escalations.length > 0
} }];
